const XLSX = require\('xlsx'\);
const workbook = XLSX.readFile\('asset_inventory_template \(3\).xlsx'\);
const sheet = workbook.Sheets[workbook.SheetNames[0]];
const data = XLSX.utils.sheet_to_json\(sheet\);

// Check last few rows
console.log\('Total rows:', data.length\);
console.log\('Last 3 rows:'\);
data.slice\(-3\).forEach\(\(row, i\) => {
  console.log\('Row', data.length - 2 + i, ':', JSON.stringify\(row\)\);
}\);

// Check all unique 'Received Date' types
const types = new Set\(\);
data.forEach\(\(row, i\) => {
  if \(row['Received Date'] !== undefined\) {
    types.add\(typeof row['Received Date'] + ':' + JSON.stringify\(row['Received Date']\)\);
  }
}\);
console.log\('\\\\nAll unique Received Date values/types:'\);
types.forEach\(t => console.log\(' ', t\)\);

// Check Under Warranty values
const warrantyVals = new Set\(\);
data.forEach\(row => {
  if \(row['Under Warranty']\) warrantyVals.add\(row['Under Warranty']\);
}\);
console.log\('\\\\nAll Under Warranty values:', [...warrantyVals]\);

// Simulate what happens with the date validation
console.log\('\\\\nDate validation test:'\);
const testDate = 46268;
if \(typeof testDate === 'number'\) {
  const excelEpoch = new Date\(1900, 0, 1\);
  const daysOffset = testDate > 59 ? testDate - 2 : testDate - 1;
  const jsDate = new Date\(excelEpoch.getTime\(\) + daysOffset * 24 * 60 * 60 * 1000\);
  console.log\('Excel serial 46268 converts to:', jsDate.toISOString\(\).split\('T'\)[0]\);
}
")
